$ErrorActionPreference="Stop"
[Console]::OutputEncoding=[System.Text.UTF8Encoding]::new()
function EnsureDir([string]$Path){if($Path -and !(Test-Path -LiteralPath $Path)){New-Item -ItemType Directory -Path $Path -Force|Out-Null}}
function WriteJsonFile([string]$Path,$Object){EnsureDir (Split-Path -Parent $Path);$Object|ConvertTo-Json -Depth 100|Set-Content -LiteralPath $Path -Encoding UTF8}
try{$out=[string]$args[0];if([string]::IsNullOrWhiteSpace($out)){$out="ENGREMIAT_MEMORY/events/plan-to-worker-events.json"};$events=@([ordered]@{type="PLAN_IMPORTED";objective_id="ENGREMIAT_PLAN_TO_WORKER_APP_001";source="data/plan-to-worker/imported-plan-raw.json";created_at=(Get-Date).ToString("s")},[ordered]@{type="STEP_SELECTED";objective_id="ENGREMIAT_PLAN_TO_WORKER_APP_001";source="data/plan-to-worker/selected-step.json";created_at=(Get-Date).ToString("s")},[ordered]@{type="PROMPT_GENERATED";objective_id="ENGREMIAT_PLAN_TO_WORKER_APP_001";source="prompts/outbox/WORKER_PROMPT.md";created_at=(Get-Date).ToString("s")},[ordered]@{type="WORKER_RESPONSE_IMPORTED";objective_id="ENGREMIAT_PLAN_TO_WORKER_APP_001";source="prompts/inbox";status="PENDING_REAL_WORKER_RESPONSE";created_at=(Get-Date).ToString("s")});WriteJsonFile $out ([ordered]@{objective_id="ENGREMIAT_PLAN_TO_WORKER_APP_001";stage="E07";events=$events;external_network=$false;git_write=$false;worker_real_execution=$false;created_at=(Get-Date).ToString("s")});Write-Host ("OK events_exported=True path="+$out)}catch{Write-Host ("ERR events_exported=False message="+$_.Exception.Message) -ForegroundColor Red;throw}
